 1	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
 2	import { CodeEditor } from '@openshift-console/dynamic-plugin-sdk';
 3	import { Card, CardBody } from '@patternfly/react-core';
 4	import { stringify } from 'yaml';
 5	
 6	const YAML = function () {
 7	  const { data: sites } = useWatchedSkupperResource({ kind: 'Site' });
 8	  const site = sites?.[0]?.rawData;
 9	
10	  return (
11	    <Card isFullHeight data-testid="yaml">
12	      <CardBody>
13	        <CodeEditor value={site ? stringify(site) : ''} options={{ readOnly: true }} minHeight={'95%'} />
14	      </CardBody>
15	    </Card>
16	  );
17	};
18	
19	export default YAML;

